import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Properly encoding user input to prevent XSS attacks
        userInput = encodeForHtml(userInput);

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>User Input: " + userInput + "</h1>"); // User input is now properly encoded
        out.println("</body>");
        out.println("</html>");
    }

    private String encodeForHtml(String input) {
        // Implement proper encoding for HTML content
        return input.replaceAll("&", "&amp;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;")
                    .replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
